import { Injectable, Optional } from "@nestjs/common";
import { TestInstance, Prisma } from "@prisma/client";

import { BaseRepository } from "../../../common";
import { PrismaService } from "../../../prisma/prisma.service";

@Injectable()
export class TestInstanceRepository extends BaseRepository<
  TestInstance,
  Prisma.TestInstanceCreateInput,
  Prisma.TestInstanceUpdateInput
> {
  constructor(
    prisma: PrismaService,
    @Optional() tx?: Prisma.TransactionClient,
  ) {
    super(prisma, "testInstance", { softDelete: false }, tx);
  }

  withTransaction(tx: Prisma.TransactionClient): this {
    return new TestInstanceRepository(this.prisma, tx) as this;
  }

  async loadDeepSnapshot(id: string): Promise<any> {
    return this.db.testInstance.findUnique({
      where: { id },
      include: {
        sections: {
          include: {
            questions: {
              orderBy: { questionOrder: 'asc' }
            }
          },
          orderBy: { orderIndex: 'asc' }
        }
      }
    });
  }
}

import { Injectable, BadRequestException, Inject } from "@nestjs/common";
import { AppLogger } from "@intervu-ai/shared-logger";
import { PrismaService } from "../../../prisma/prisma.service";
import { ExecutionValidatorService } from "./execution-validator.service";
import { ExecutionStateService } from "./execution-state.service";
import { CandidateAnswerRepository } from "../repositories";
import { CandidateAnswerDto } from "../dto";
import { Prisma } from "@prisma/client";

@Injectable()
export class AnswerService {
  private readonly logger = new AppLogger({ name: "AnswerService" });

  constructor(
    private readonly prisma: PrismaService,
    private readonly validator: ExecutionValidatorService,
    private readonly stateService: ExecutionStateService,
    private readonly answerRepo: CandidateAnswerRepository,
  ) {}

  async saveAnswer(
    testInstanceId: string,
    userId: string,
    dto: CandidateAnswerDto,
  ): Promise<{ status: string }> {
    this.logger.debug("Saving candidate answer", { testInstanceId, questionId: dto.questionId });
    return this.prisma.$transaction(async (tx) => {
      // 1. Fetch test instance
      const testInstance = await this.validator.validateAssessment(testInstanceId, tx);

      // 2. Validate ownership
      this.validator.validateOwnership(testInstance, userId);

      // 3. Validate state (not submitted)
      this.validator.validateSubmissionState(testInstance);

      // 4. Load execution state
      const executionState = await this.stateService.restoreProgress(testInstanceId, tx);

      // 5. Validate timer
      const { isExpired, actualRemainingTime } = this.validator.validateTimer(
        testInstance,
        executionState,
        dto.timeSpentSeconds ? (executionState?.remainingTimeSeconds || 0) - dto.timeSpentSeconds : undefined
      );

      if (isExpired) {
        this.logger.warn("Timer expired during autosave", { testInstanceId, userId });
        return { status: "expired" };
      }

      // 6. Validate question
      this.validator.validateQuestion(testInstanceId, dto.questionId);

      // 7. Persist Answer
      const repo = this.answerRepo.withTransaction(tx);
      const existingAnswers = await repo.findAll({ testInstanceId, questionId: dto.questionId });
      const existing = existingAnswers[0];

      if (existing) {
        await repo.update(existing.id, {
          answer: dto.answer as unknown as Prisma.InputJsonValue,
          timeSpentSeconds: existing.timeSpentSeconds + (dto.timeSpentSeconds || 0),
          isMarkedForReview: dto.isMarkedForReview !== undefined ? dto.isMarkedForReview : existing.isMarkedForReview,
          savedAt: new Date(),
        });
      } else {
        await repo.create({
          testInstance: { connect: { id: testInstanceId } },
          questionId: dto.questionId,
          answer: dto.answer as unknown as Prisma.InputJsonValue,
          timeSpentSeconds: dto.timeSpentSeconds || 0,
          isMarkedForReview: dto.isMarkedForReview || false,
          savedAt: new Date(),
        });
      }

      // 8. Update Execution State
      const newRemainingTime = Math.max(0, actualRemainingTime);
      await this.stateService.saveProgress(
        testInstanceId,
        executionState?.currentQuestionIndex || 0,
        newRemainingTime,
        tx
      );

      this.logger.debug("Answer saved successfully", { testInstanceId, questionId: dto.questionId });
      return { status: "saved" };
    });
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { ExecutionStateService } from './execution-state.service';
import { ExecutionStateRepository } from '../repositories';
import { Prisma } from '@prisma/client';

describe('ExecutionStateService', () => {
  let service: ExecutionStateService;
  let repo: jest.Mocked<ExecutionStateRepository>;

  beforeEach(async () => {
    const repoMock = {
      findAll: jest.fn(),
      update: jest.fn(),
      create: jest.fn(),
      withTransaction: jest.fn().mockReturnThis(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        ExecutionStateService,
        {
          provide: ExecutionStateRepository,
          useValue: repoMock,
        },
      ],
    }).compile();

    service = module.get<ExecutionStateService>(ExecutionStateService);
    repo = module.get(ExecutionStateRepository);
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('saveProgress', () => {
    it('should update existing state if found', async () => {
      repo.findAll.mockResolvedValueOnce([{ id: 'state_1' } as any]);
      repo.update.mockResolvedValueOnce({ id: 'state_1', currentQuestionIndex: 1, remainingTimeSeconds: 500 } as any);

      const result = await service.saveProgress('test_1', 1, 500);

      expect(repo.findAll).toHaveBeenCalledWith({ testInstanceId: 'test_1' });
      expect(repo.update).toHaveBeenCalledWith('state_1', expect.objectContaining({
        currentQuestionIndex: 1,
        remainingTimeSeconds: 500,
      }));
      expect(result.remainingTimeSeconds).toBe(500);
    });

    it('should create new state if none exists', async () => {
      repo.findAll.mockResolvedValueOnce([]);
      repo.create.mockResolvedValueOnce({ id: 'state_new', currentQuestionIndex: 2, remainingTimeSeconds: 300 } as any);

      const result = await service.saveProgress('test_2', 2, 300);

      expect(repo.findAll).toHaveBeenCalledWith({ testInstanceId: 'test_2' });
      expect(repo.create).toHaveBeenCalledWith(expect.objectContaining({
        currentQuestionIndex: 2,
        remainingTimeSeconds: 300,
      }));
      expect(result.id).toBe('state_new');
    });
  });

  describe('restoreProgress', () => {
    it('should return null if no state', async () => {
      repo.findAll.mockResolvedValueOnce([]);
      const result = await service.restoreProgress('test_1');
      expect(result).toBeNull();
    });

    it('should return first state if exists', async () => {
      repo.findAll.mockResolvedValueOnce([{ id: 'state_1', currentQuestionIndex: 5 } as any]);
      const result = await service.restoreProgress('test_1');
      expect(result?.currentQuestionIndex).toBe(5);
    });
  });
});

import { Injectable, NotFoundException } from "@nestjs/common";
import { ExecutionState } from "@prisma/client";
import { ExecutionStateRepository } from "../repositories";
import { Prisma } from "@prisma/client";

@Injectable()
export class ExecutionStateService {
  constructor(private readonly executionStateRepo: ExecutionStateRepository) {}

  async saveProgress(
    testInstanceId: string,
    currentQuestionIndex: number,
    remainingTimeSeconds: number,
    tx?: Prisma.TransactionClient,
  ): Promise<ExecutionState> {
    const repo = tx ? this.executionStateRepo.withTransaction(tx) : this.executionStateRepo;

    const existingStates = await repo.findAll({ testInstanceId });
    const existing = existingStates[0];

    if (existing) {
      return repo.update(existing.id, {
        currentQuestionIndex,
        remainingTimeSeconds,
        lastActivityAt: new Date(),
      });
    }

    return repo.create({
      testInstance: { connect: { id: testInstanceId } },
      currentQuestionIndex,
      remainingTimeSeconds,
      lastActivityAt: new Date(),
    });
  }

  async restoreProgress(
    testInstanceId: string,
    tx?: Prisma.TransactionClient,
  ): Promise<ExecutionState | null> {
    const repo = tx ? this.executionStateRepo.withTransaction(tx) : this.executionStateRepo;
    const existingStates = await repo.findAll({ testInstanceId });
    return existingStates[0] || null;
  }
}

import { Test, TestingModule } from '@nestjs/testing';
import { ExecutionValidatorService } from './execution-validator.service';
import { TestInstanceRepository } from '../repositories';
import { ForbiddenException, NotFoundException, ConflictException, BadRequestException } from '@nestjs/common';

describe('ExecutionValidatorService', () => {
  let service: ExecutionValidatorService;
  let repo: jest.Mocked<TestInstanceRepository>;

  beforeEach(async () => {
    const repoMock = {
      findById: jest.fn(),
      withTransaction: jest.fn().mockReturnThis(),
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        ExecutionValidatorService,
        {
          provide: TestInstanceRepository,
          useValue: repoMock,
        },
      ],
    }).compile();

    service = module.get<ExecutionValidatorService>(ExecutionValidatorService);
    repo = module.get(TestInstanceRepository);
  });

  it('should be defined', () => {
    expect(service).toBeDefined();
  });

  describe('validateAssessment', () => {
    it('should throw NotFound if assessment is missing', async () => {
      repo.findById.mockResolvedValueOnce(null);
      await expect(service.validateAssessment('test_1')).rejects.toThrow(NotFoundException);
    });

    it('should return assessment if exists', async () => {
      repo.findById.mockResolvedValueOnce({ id: 'test_1' } as any);
      const res = await service.validateAssessment('test_1');
      expect(res.id).toBe('test_1');
    });
  });

  describe('validateOwnership', () => {
    it('should throw Forbidden if user is different', () => {
      expect(() => service.validateOwnership({ userId: 'user_1' } as any, 'user_2')).toThrow(ForbiddenException);
    });

    it('should not throw if user matches', () => {
      expect(() => service.validateOwnership({ userId: 'user_1' } as any, 'user_1')).not.toThrow();
    });
  });

  describe('validateSubmissionState', () => {
    it('should throw Conflict if already submitted', () => {
      expect(() => service.validateSubmissionState({ status: 'SUBMITTED' } as any)).toThrow(ConflictException);
    });

    it('should not throw if active', () => {
      expect(() => service.validateSubmissionState({ status: 'ACTIVE' } as any)).not.toThrow();
    });
  });
});

import {
  Injectable,
  NotFoundException,
  ForbiddenException,
  ConflictException,
  BadRequestException,
} from "@nestjs/common";
import { AppLogger } from "@intervu-ai/shared-logger";
import { TestInstance, ExecutionState } from "@prisma/client";
import { TestInstanceRepository } from "../repositories";

@Injectable()
export class ExecutionValidatorService {
  private readonly logger = new AppLogger({ name: "ExecutionValidatorService" });

  constructor(private readonly testInstanceRepo: TestInstanceRepository) {}

  async validateAssessment(testInstanceId: string, tx?: any): Promise<TestInstance> {
    const repo = tx ? this.testInstanceRepo.withTransaction(tx) : this.testInstanceRepo;
    const testInstance = await repo.findById(testInstanceId);

    if (!testInstance) {
      this.logger.warn("Validation failed: Assessment not found", { testInstanceId });
      throw new NotFoundException({
        code: "ASSESSMENT_NOT_FOUND",
        message: "Assessment not found",
      });
    }

    return testInstance;
  }

  validateOwnership(testInstance: TestInstance, userId: string): void {
    if (testInstance.userId !== userId) {
      this.logger.warn("Validation failed: Ownership check failed", { testInstanceId: testInstance.id, userId });
      throw new ForbiddenException({
        code: "FORBIDDEN",
        message: "You do not own this assessment",
      });
    }
  }

  validateSubmissionState(testInstance: TestInstance): void {
    if (testInstance.status === "SUBMITTED" || testInstance.status === "COMPLETED") {
      this.logger.warn("Validation failed: Assessment already submitted", { testInstanceId: testInstance.id, status: testInstance.status });
      throw new ConflictException({
        code: "ASSESSMENT_ALREADY_SUBMITTED",
        message: "Assessment has already been submitted",
      });
    }
  }

  validateTimer(
    testInstance: TestInstance,
    executionState: ExecutionState | null,
    providedRemainingTime?: number,
  ): { isExpired: boolean; actualRemainingTime: number } {
    if (testInstance.expiresAt && testInstance.expiresAt < new Date()) {
      return { isExpired: true, actualRemainingTime: 0 };
    }

    if (executionState && executionState.remainingTimeSeconds <= 0) {
      return { isExpired: true, actualRemainingTime: 0 };
    }

    // Backend authoritative remaining time takes precedence over provided remaining time.
    let actualRemainingTime = executionState?.remainingTimeSeconds ?? providedRemainingTime ?? 0;

    if (testInstance.expiresAt) {
       const timeToExpiry = Math.floor((testInstance.expiresAt.getTime() - Date.now()) / 1000);
       if (timeToExpiry <= 0) {
           return { isExpired: true, actualRemainingTime: 0 };
       }
       if (actualRemainingTime === 0 || timeToExpiry < actualRemainingTime) {
           actualRemainingTime = timeToExpiry;
       }
    }

    return {
      isExpired: actualRemainingTime <= 0,
      actualRemainingTime,
    };
  }

  validateQuestion(
    testInstanceId: string,
    questionId: string,
  ): void {
    if (!questionId) {
       this.logger.warn("Validation failed: Invalid question ID", { testInstanceId, questionId });
       throw new BadRequestException({
         code: "INVALID_QUESTION",
         message: "Question ID is invalid",
       });
    }
  }
}

import { Injectable, NotFoundException } from "@nestjs/common";
import { AppLogger } from "@intervu-ai/shared-logger";
import { PrismaService } from "../../../prisma/prisma.service";
import { TestInstanceRepository } from "../repositories";
import { ExecutionValidatorService } from "./execution-validator.service";

@Injectable()
export class ExecutionService {
  private readonly logger = new AppLogger({ name: "ExecutionService" });

  constructor(
    private readonly prisma: PrismaService,
    private readonly testInstanceRepo: TestInstanceRepository,
    private readonly validator: ExecutionValidatorService,
  ) {}

  async loadAssessment(testInstanceId: string, userId: string): Promise<any> {
    this.logger.debug("Loading assessment snapshot", { testInstanceId, userId });
    // 1. Validate assessment exists
    const testInstance = await this.validator.validateAssessment(testInstanceId);

    // 2. Validate ownership
    this.validator.validateOwnership(testInstance, userId);

    // 3. Load full snapshot (sections, questions)
    // We use the repository method for deep relational loading to avoid bypassing the abstraction layer
    const snapshot = await this.testInstanceRepo.loadDeepSnapshot(testInstanceId);

    if (!snapshot) {
      throw new NotFoundException("Assessment snapshot could not be loaded");
    }

    return {
      testInstanceId: snapshot.id,
      testConfigId: snapshot.testConfigId,
      status: snapshot.status,
      expiresAt: snapshot.expiresAt,
      sections: snapshot.sections.map((section: { id: any; sectionKey: any; sectionName: any; durationSeconds: any; questions: any[]; }) => ({
        sectionId: section.id,
        sectionKey: section.sectionKey,
        sectionName: section.sectionName,
        durationSeconds: section.durationSeconds,
        questions: section.questions.map(q => ({
          questionId: q.questionId,
          questionOrder: q.questionOrder,
          snapshot: q.questionSnapshot,
        }))
      }))
    };
  }
}

import { Injectable } from "@nestjs/common";
import { AppLogger } from "@intervu-ai/shared-logger";
import { ExecutionValidatorService } from "./execution-validator.service";
import { ExecutionStateService } from "./execution-state.service";
import { CandidateAnswerRepository } from "../repositories";

@Injectable()
export class ResumeService {
  private readonly logger = new AppLogger({ name: "ResumeService" });

  constructor(
    private readonly validator: ExecutionValidatorService,
    private readonly stateService: ExecutionStateService,
    private readonly answerRepo: CandidateAnswerRepository,
  ) {}

  async resumeAssessment(testInstanceId: string, userId: string): Promise<any> {
    this.logger.debug("Resuming assessment", { testInstanceId, userId });
    // 1. Validate assessment exists
    const testInstance = await this.validator.validateAssessment(testInstanceId);

    // 2. Validate ownership
    this.validator.validateOwnership(testInstance, userId);

    // 3. Check if submitted (we might still allow resume/viewing if submitted, but let's check)
    // The prompt says "Support interrupted sessions", meaning it's active.

    // 4. Fetch execution state
    const executionState = await this.stateService.restoreProgress(testInstanceId);

    // 5. Fetch candidate answers
    const answers = await this.answerRepo.findAll({ testInstanceId });

    return {
      testInstanceId,
      status: testInstance.status,
      executionState: executionState ? {
        currentQuestionIndex: executionState.currentQuestionIndex,
        remainingTimeSeconds: executionState.remainingTimeSeconds,
      } : null,
      answers: answers.map(a => ({
        questionId: a.questionId,
        answer: a.answer,
        timeSpentSeconds: a.timeSpentSeconds,
        isMarkedForReview: a.isMarkedForReview,
        savedAt: a.savedAt,
      })),
    };
  }
}

import { Injectable, Inject, NotFoundException } from "@nestjs/common";
import { AppLogger } from "@intervu-ai/shared-logger";
import { PrismaService } from "../../../prisma/prisma.service";
import { ExecutionValidatorService } from "./execution-validator.service";
import { TestInstanceRepository, SubmissionRepository, CandidateAnswerRepository } from "../repositories";
import { EVALUATION_ADAPTER, EvaluationAdapter } from "../interfaces/evaluation-adapter.interface";
import { ExecutionResultDto } from "../dto";

@Injectable()
export class SubmissionService {
  private readonly logger = new AppLogger({ name: "SubmissionService" });

  constructor(
    private readonly prisma: PrismaService,
    private readonly validator: ExecutionValidatorService,
    private readonly testInstanceRepo: TestInstanceRepository,
    private readonly submissionRepo: SubmissionRepository,
    private readonly answerRepo: CandidateAnswerRepository,
    @Inject(EVALUATION_ADAPTER) private readonly evaluationAdapter: EvaluationAdapter,
  ) {}

  async submitAssessment(testInstanceId: string, userId: string, isAutoSubmit = false): Promise<{ submissionId: string; status: string }> {
    this.logger.info("Initiating assessment submission", { testInstanceId, userId, isAutoSubmit });

    const { submission, executionResult } = await this.prisma.$transaction(async (tx) => {
      // 1. Lock and fetch assessment
      const testInstance = await this.validator.validateAssessment(testInstanceId, tx);

      // 2. Ownership
      this.validator.validateOwnership(testInstance, userId);

      // 3. Check if already submitted
      this.validator.validateSubmissionState(testInstance);

      // 5. Update Status to SUBMITTED
      const repo = this.testInstanceRepo.withTransaction(tx);
      await repo.update(testInstance.id, {
        status: "SUBMITTED",
        submittedAt: new Date(),
      });

      // 6. Create Submission record
      const subRepo = this.submissionRepo.withTransaction(tx);
      const submission = await subRepo.create({
        testInstance: { connect: { id: testInstanceId } },
        status: "SUBMITTED",
        submittedAt: new Date(),
      });

      // 7. Collect answers for Evaluation
      const ansRepo = this.answerRepo.withTransaction(tx);
      const answers = await ansRepo.findAll({ testInstanceId });

      const executionResult: ExecutionResultDto = {
        executionId: submission.id,
        testId: testInstanceId,
        status: "submitted",
        submittedAt: new Date(),
        answers: answers.map(a => ({
          questionId: a.questionId,
          answer: String(a.answer), // assuming scalar for now
          timeSpentSeconds: a.timeSpentSeconds,
          isMarkedForReview: a.isMarkedForReview,
        })),
      };

      return { submission, executionResult };
    });

    this.logger.info("Transaction committed successfully, triggering evaluation", { 
      submissionId: submission.id, 
      testInstanceId 
    });

    // 8. Trigger Evaluation (Mocked via DI adapter) outside the DB transaction
    // This prevents slow evaluation engines from blocking DB connections
    await this.evaluationAdapter.triggerEvaluation(executionResult);

    return {
      submissionId: submission.id,
      status: isAutoSubmit ? "EXPIRED_AND_SUBMITTED" : "SUBMITTED",
    };
  }
}
